#!/bin/bash
# Export script for Analytical Window Queries task
# Analyzes the text files generated by the agent and the SQL script

echo "=== Exporting Analytical Window Queries Results ==="
source /workspace/scripts/task_utils.sh

# Capture final screenshot
take_screenshot /tmp/task_final.png

# Paths
Q1_FILE="/home/ga/Desktop/salary_percentiles.txt"
Q2_FILE="/home/ga/Desktop/dept_budget_analysis.txt"
Q3_FILE="/home/ga/Desktop/turnover_risk.txt"
Q4_FILE="/home/ga/Desktop/salary_pivot.txt"
SQL_FILE="/home/ga/Desktop/analytical_queries.sql"
TASK_START=$(cat /tmp/task_start_time.txt 2>/dev/null || echo "0")

# Python script to analyze files and dump JSON result
python3 << PYEOF
import json
import os
import re
import time

def get_file_stats(path):
    if not os.path.exists(path):
        return {"exists": False, "lines": 0, "size": 0, "modified_after_start": False}
    
    mtime = os.path.getmtime(path)
    start_time = float($TASK_START)
    
    try:
        with open(path, 'r', errors='ignore') as f:
            lines = [l.strip() for l in f.readlines() if l.strip()]
            content = "\\n".join(lines)
    except:
        lines = []
        content = ""

    return {
        "exists": True,
        "lines": len(lines),
        "size": os.path.getsize(path),
        "modified_after_start": mtime > start_time,
        "content_head": lines[:5] if lines else [],
        "content_sample_king": [l for l in lines if "King" in l and "100" in l],
        "content_sample_olson": [l for l in lines if "Olson" in l and "132" in l],
        "raw_content_start": content[:500]
    }

def analyze_sql_script(path):
    stats = get_file_stats(path)
    if not stats["exists"]:
        return stats
    
    content = stats["raw_content_start"].upper() # Just checking start isn't enough for full keywords, need full read
    try:
        with open(path, 'r', errors='ignore') as f:
            full_content = f.read().upper()
    except:
        full_content = ""
        
    keywords = {
        "RANK": "RANK" in full_content,
        "DENSE_RANK": "DENSE_RANK" in full_content,
        "PERCENT_RANK": "PERCENT_RANK" in full_content,
        "NTILE": "NTILE" in full_content,
        "OVER": "OVER" in full_content,
        "PARTITION": "PARTITION" in full_content,
        "WITH": "WITH" in full_content, # CTE check
        "PIVOT": "PIVOT" in full_content or "DECODE" in full_content or "CASE" in full_content,
        "SUM": "SUM" in full_content
    }
    
    # Count semicolons roughly indicates number of queries
    query_count = full_content.count(";")
    
    stats.update({"keywords": keywords, "estimated_query_count": query_count})
    return stats

results = {
    "q1": get_file_stats("$Q1_FILE"),
    "q2": get_file_stats("$Q2_FILE"),
    "q3": get_file_stats("$Q3_FILE"),
    "q4": get_file_stats("$Q4_FILE"),
    "sql": analyze_sql_script("$SQL_FILE"),
    "task_start": $TASK_START,
    "export_time": time.time()
}

with open("/tmp/task_result.json", "w") as f:
    json.dump(results, f, indent=2)

PYEOF

# Ensure permissions
chmod 666 /tmp/task_result.json

echo "Results exported to /tmp/task_result.json"
cat /tmp/task_result.json
echo "=== Export Complete ==="